package com.chaobo.scm.supplier.infrastructure.persistence.integration;
import com.chaobo.scm.supplier.application.integration.*;import org.springframework.stereotype.Repository;import java.time.OffsetDateTime;import java.util.List;
@Repository public class MyBatisIntegrationCommandRepository implements IntegrationCommandRepository{private final IntegrationCommandMapper mapper;public MyBatisIntegrationCommandRepository(IntegrationCommandMapper mapper){this.mapper=mapper;}public void save(IntegrationCommand c){mapper.insert(c);}public List<IntegrationCommand> lockDispatchable(int size){return mapper.lockDispatchable(size);}public boolean markExecuting(long id){return mapper.markExecuting(id)==1;}public void markSucceeded(long id,String reference){mapper.markSucceeded(id,reference);}public void markRetry(long id,int expectedRetry,OffsetDateTime nextRetry,String reason,int maxRetries){mapper.markRetry(id,expectedRetry,nextRetry,reason,maxRetries);}public void retryManually(long id,String reason){mapper.retryManually(id,reason);}}
